class Solution {
public:
    string smallestNumber(string pattern) {
        int n = pattern.size();
        string num(n + 1, ' ');
        int low = 1, high = n + 1;
        for (int i = 0; i <= n; ++i) {
            if (i == n || pattern[i] == 'I') {
                num[i] = '0' + low++;
                while (i > 0 && pattern[i - 1] == 'D') {
                    num[--i] = '0' + low++;
                }
            }
        }
        return num;
    }
};
